
import AsyncStorage from '@react-native-async-storage/async-storage';

const KEY = 'gl_v8';

const toArray = (value) => {
  if (value instanceof Set) return [...value];
  if (Array.isArray(value)) return value;
  return [];
};

const toSet = (value) => new Set(toArray(value));

const normalizeStateForSave = (state = {}) => ({
  ...state,
  attendance: toArray(state.attendance),
  attendanceData: state.attendanceData && typeof state.attendanceData === 'object' ? state.attendanceData : {},
  holidays: Array.isArray(state.holidays) ? state.holidays : [],
  leavePlans: Array.isArray(state.leavePlans) ? state.leavePlans : [],
  leaveCats: state.leaveCats && typeof state.leaveCats === 'object' ? state.leaveCats : {},
});

const normalizeStateFromStorage = (parsed) => {
  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return null;
  return {
    ...parsed,
    attendance: toSet(parsed.attendance),
    attendanceData: parsed.attendanceData && typeof parsed.attendanceData === 'object' ? parsed.attendanceData : {},
    holidays: Array.isArray(parsed.holidays) ? parsed.holidays : [],
    leavePlans: Array.isArray(parsed.leavePlans) ? parsed.leavePlans : [],
    leaveCats: parsed.leaveCats && typeof parsed.leaveCats === 'object' ? parsed.leaveCats : {},
  };
};

export const saveState = async (state) => {
  try {
    const toSave = normalizeStateForSave(state);
    await AsyncStorage.setItem(KEY, JSON.stringify(toSave));
    console.log('[Storage] Saved successfully');
    return true;
  } catch (err) {
    console.warn('[Storage] Save failed:', err);
    return false;
  }
};

export const loadState = async () => {
  try {
    const raw = await AsyncStorage.getItem(KEY);
    if (!raw) { console.log('[Storage] No saved state'); return null; }
    const parsed = JSON.parse(raw);
    const normalized = normalizeStateFromStorage(parsed);
    if (!normalized) return null;
    console.log('[Storage] Loaded successfully');
    return normalized;
  } catch (err) {
    console.warn('[Storage] Load failed:', err);
    return null;
  }
};

export const clearState = async () => {
  try {
    await AsyncStorage.removeItem(KEY);
    console.log('[Storage] Cleared');
    return true;
  } catch (err) {
    console.warn('[Storage] Clear failed:', err);
    return false;
  }
};
